import re

def detect_secrets_in_message(message):
    patterns = [
        r'\b(sk-[a-zA-Z0-9]{48})\b',  # OpenAI keys
        r'\b(ak-[a-zA-Z0-9]{32})\b',  # Anthropic keys
        r'Bearer\s+[a-zA-Z0-9_-]+',   # Bearer tokens
        r'[a-zA-Z0-9]{8}-[a-zA-Z0-9]{4}-[a-zA-Z0-9]{4}-[a-zA-Z0-9]{4}-[a-zA-Z0-9]{12}',  # UUIDs
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'  # Emails
    ]
    content = message.get('content', '')
    for pattern in patterns:
        if re.search(pattern, content):
            return {'type': 'sensitive_data', 'pattern': pattern, 'content': content[:100]}
    return None

