import re

def scan_code_for_secrets(code_str):
    tree = ast.parse(code_str)
    secrets = []
    for node in ast.walk(tree):
        if isinstance(node, ast.Str) and len(node.s) > 20:
            if re.search(r'(sk-|ak-|Bearer|key=|password=|secret=)', node.s):
                secrets.append({
                    'line': node.lineno,
                    'value': node.s[:20] + '...' if len(node.s) > 20 else node.s
                })
    return secrets

