import re

def redact_secrets(text):
    patterns = {
        r'\b(sk-[a-zA-Z0-9]{48})\b': '[REDACTED_API_KEY]',
        r'Bearer\s+[a-zA-Z0-9_-]+': 'Bearer [REDACTED_TOKEN]',
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[REDACTED_EMAIL]'
    }
    for pattern, replacement in patterns.items():
        text = re.sub(pattern, replacement, text)
    return text

def safe_reply_function(messages, sender, config):
    latest_msg = messages[-1]
    safe_content = redact_secrets(latest_msg.get('content', ''))
    if safe_content != latest_msg.get('content', ''):
        latest_msg['content'] = safe_content
        print('Message redacted before forwarding')
    return None
